it("should handle multiple cells together", () => {
  // Multiple cells in different positions evolving simultaneously
  const grid = new Set(["0,0", "1,0", "2,0"]);
  expect(nextGeneration(grid)).toEqual(new Set(["1,-1", "1,0", "1,1"]));
});
